**PRODUCTION PATTERN**:

```go
package main

import (
	"context"
	"encoding/json"
	"log"
	"net/http"
	"os"
	"strings"
	"time"
)

// SecurityConfig holds environment-specific security settings
type SecurityConfig struct {
	AllowedOrigins   []string
	AllowedMethods   []string
	AllowedHeaders   []string
	ExposeHeaders    []string
	MaxAge           int
	AllowCredentials bool
	HSTSMaxAge       int
	CSPPolicy        string
	Environment      string
}

// Logger interface for structured logging
type Logger interface {
	Info(msg string, fields map[string]interface{})
	Warn(msg string, fields map[string]interface{})
	Error(msg string, fields map[string]interface{})
}

// SimpleLogger implements basic structured logging
type SimpleLogger struct{}

func (l *SimpleLogger) Info(msg string, fields map[string]interface{}) {
	log.Printf("INFO: %s %v", msg, fields)
}

func (l *SimpleLogger) Warn(msg string, fields map[string]interface{}) {
	log.Printf("WARN: %s %v", msg, fields)
}

func (l *SimpleLogger) Error(msg string, fields map[string]interface{}) {
	log.Printf("ERROR: %s %v", msg, fields)
}

var logger Logger = &SimpleLogger{}

// LoadSecurityConfig loads configuration based on environment
func LoadSecurityConfig() *SecurityConfig {
	env := os.Getenv("APP_ENV")
	if env == "" {
		env = "development"
	}

	config := &SecurityConfig{
		Environment:      env,
		AllowedMethods:   []string{"GET", "POST", "PUT", "DELETE", "OPTIONS"},
		AllowedHeaders:   []string{"Content-Type", "Authorization", "X-Request-ID"},
		ExposeHeaders:    []string{"X-Request-ID", "X-RateLimit-Remaining"},
		MaxAge:           86400,
		AllowCredentials: true,
	}

	switch env {
	case "production":
		config.AllowedOrigins = strings.Split(os.Getenv("ALLOWED_ORIGINS"), ",")
		config.HSTSMaxAge = 31536000 // 1 year
		config.CSPPolicy = "default-src 'none'; frame-ancestors 'none'; base-uri 'self'"
	case "staging":
		config.AllowedOrigins = []string{"https://staging.example.com", "https://staging-admin.example.com"}
		config.HSTSMaxAge = 86400 // 1 day for staging
		config.CSPPolicy = "default-src 'self'; frame-ancestors 'none'"
	default: // development
		config.AllowedOrigins = []string{"http://localhost:3000", "http://localhost:8080"}
		config.HSTSMaxAge = 0
		config.CSPPolicy = "default-src 'self' 'unsafe-inline'"
	}

	return config
}

// isOriginAllowed checks if the origin is in the allowed list
func isOriginAllowed(origin string, allowed []string) bool {
	for _, o := range allowed {
		if o == origin || o == "*" {
			return true
		}
	}
	return false
}

// SecurityHeadersMiddleware adds comprehensive security headers
func SecurityHeadersMiddleware(config *SecurityConfig) func(http.Handler) http.Handler {
	return func(next http.Handler) http.Handler {
		return http.HandlerFunc(func(w http.ResponseWriter, r *http.Request) {
			origin := r.Header.Get("Origin")
			requestID := r.Header.Get("X-Request-ID")
			if requestID == "" {
				requestID = generateRequestID()
			}

			// Add request ID to context for tracing
			ctx := context.WithValue(r.Context(), "requestID", requestID)
			r = r.WithContext(ctx)

			// === CORS Headers ===
			if origin != "" && isOriginAllowed(origin, config.AllowedOrigins) {
				w.Header().Set("Access-Control-Allow-Origin", origin)
				w.Header().Set("Access-Control-Allow-Methods", strings.Join(config.AllowedMethods, ", "))
				w.Header().Set("Access-Control-Allow-Headers", strings.Join(config.AllowedHeaders, ", "))
				w.Header().Set("Access-Control-Expose-Headers", strings.Join(config.ExposeHeaders, ", "))
				w.Header().Set("Access-Control-Max-Age", "86400")
				if config.AllowCredentials {
					w.Header().Set("Access-Control-Allow-Credentials", "true")
				}
			} else if origin != "" {
				// Log blocked CORS requests for security monitoring
				logger.Warn("CORS request from unauthorized origin", map[string]interface{}{
					"origin":     origin,
					"path":       r.URL.Path,
					"method":     r.Method,
					"request_id": requestID,
					"ip":         r.RemoteAddr,
				})
			}

			// Handle preflight requests
			if r.Method == "OPTIONS" {
				w.WriteHeader(http.StatusNoContent)
				return
			}

			// === Security Headers ===
			// Prevent clickjacking
			w.Header().Set("X-Frame-Options", "DENY")

			// Prevent MIME sniffing
			w.Header().Set("X-Content-Type-Options", "nosniff")

			// XSS Protection (legacy browsers)
			w.Header().Set("X-XSS-Protection", "1; mode=block")

			// Content Security Policy
			w.Header().Set("Content-Security-Policy", config.CSPPolicy)

			// Referrer Policy
			w.Header().Set("Referrer-Policy", "strict-origin-when-cross-origin")

			// Permissions Policy (formerly Feature-Policy)
			w.Header().Set("Permissions-Policy", "geolocation=(), microphone=(), camera=(), payment=()")

			// HSTS (only in production with HTTPS)
			if config.HSTSMaxAge > 0 {
				w.Header().Set("Strict-Transport-Security",
					"max-age="+string(rune(config.HSTSMaxAge))+"; includeSubDomains; preload")
			}

			// Remove server information leakage
			w.Header().Set("Server", "")
			w.Header().Del("X-Powered-By")

			// Request ID for tracing
			w.Header().Set("X-Request-ID", requestID)

			// Cache control for API responses
			w.Header().Set("Cache-Control", "no-store, no-cache, must-revalidate, private")
			w.Header().Set("Pragma", "no-cache")
			w.Header().Set("Expires", "0")

			next.ServeHTTP(w, r)
		})
	}
}

// generateRequestID creates a simple request ID (use UUID in production)
func generateRequestID() string {
	return time.Now().Format("20060102150405") + "-" + randomString(8)
}

func randomString(n int) string {
	const letters = "abcdefghijklmnopqrstuvwxyz0123456789"
	b := make([]byte, n)
	for i := range b {
		b[i] = letters[time.Now().UnixNano()%int64(len(letters))]
	}
	return string(b)
}

// SecurityAuditMiddleware logs all requests for security monitoring
func SecurityAuditMiddleware(next http.Handler) http.Handler {
	return http.HandlerFunc(func(w http.ResponseWriter, r *http.Request) {
		start := time.Now()
		requestID := r.Context().Value("requestID")

		// Create response wrapper to capture status code
		rw := &responseWriter{ResponseWriter: w, statusCode: http.StatusOK}

		next.ServeHTTP(rw, r)

		// Log request details for security monitoring
		logger.Info("API Request", map[string]interface{}{
			"request_id":   requestID,
			"method":       r.Method,
			"path":         r.URL.Path,
			"status":       rw.statusCode,
			"duration_ms":  time.Since(start).Milliseconds(),
			"ip":           r.RemoteAddr,
			"user_agent":   r.UserAgent(),
			"origin":       r.Header.Get("Origin"),
			"content_type": r.Header.Get("Content-Type"),
		})
	})
}

type responseWriter struct {
	http.ResponseWriter
	statusCode int
}

func (rw *responseWriter) WriteHeader(code int) {
	rw.statusCode = code
	rw.ResponseWriter.WriteHeader(code)
}

// Sample API handler
func getUserHandler(w http.ResponseWriter, r *http.Request) {
	type User struct {
		ID    int    `json:"id"`
		Name  string `json:"name"`
		Email string `json:"email"`
	}

	user := User{ID: 1, Name: "John Doe", Email: "john@example.com"}

	w.Header().Set("Content-Type", "application/json")
	if err := json.NewEncoder(w).Encode(user); err != nil {
		logger.Error("Failed to encode response", map[string]interface{}{
			"error": err.Error(),
		})
		http.Error(w, "Internal Server Error", http.StatusInternalServerError)
	}
}

func main() {
	config := LoadSecurityConfig()

	logger.Info("Starting server", map[string]interface{}{
		"environment":     config.Environment,
		"allowed_origins": config.AllowedOrigins,
	})

	mux := http.NewServeMux()
	mux.HandleFunc("/api/user", getUserHandler)

	// Chain middleware: Audit -> Security Headers -> Handler
	handler := SecurityAuditMiddleware(SecurityHeadersMiddleware(config)(mux))

	server := &http.Server{
		Addr:         ":8080",
		Handler:      handler,
		ReadTimeout:  15 * time.Second,
		WriteTimeout: 15 * time.Second,
		IdleTimeout:  60 * time.Second,
	}

	log.Fatal(server.ListenAndServe())
}
```

**Defense in Depth Layers**:

1. **Origin Validation Layer**:
```go
// Strict origin validation - never use wildcard with credentials
if origin != "" && isOriginAllowed(origin, config.AllowedOrigins) {
    w.Header().Set("Access-Control-Allow-Origin", origin)
} else if origin != "" {
    // Log and alert on suspicious origins
    logger.Warn("Blocked CORS request", map[string]interface{}{"origin": origin})
}
```

2. **Content Security Policy Layer**:
