```dockerfile
# nginx/Dockerfile.production - Production-hardened nginx with nonce support
FROM nginx:1.25-alpine AS builder

# Install njs module for dynamic CSP nonces
RUN apk add --no-cache nginx-mod-http-js

FROM nginx:1.25-alpine

# Copy njs module
COPY --from=builder /usr/lib/nginx/modules/ngx_http_js_module.so /usr/lib/nginx/modules/

# Create non-root user
RUN addgroup -g 1001 -S nginx-app && \
    adduser -u 1001 -S nginx-app -G nginx-app && \
    rm -rf /usr/share/nginx/html/* && \
    mkdir -p /var/cache/nginx /var/run /var/log/nginx && \
    chown -R nginx-app:nginx-app /var/cache/nginx /var/run /var/log/nginx /etc/nginx

# Copy configuration files
COPY --chown=nginx-app:nginx-app nginx.conf /etc/nginx/nginx.conf
COPY --chown=nginx-app:nginx-app security-headers.conf /etc/nginx/snippets/security-headers.conf
COPY --chown=nginx-app:nginx-app csp-nonce.js /etc/nginx/njs/csp-nonce.js

USER nginx-app

