Yes, security headers are critical! Without them, your application is vulnerable to clickjacking, XSS, MIME sniffing attacks, and more. The 2022 Heroku/Travis CI incident showed how missing headers enabled attackers to steal OAuth tokens through clickjacking.

**VULNERABLE CODE**:

```javascript
const express = require('express');
const app = express();

app.use(express.json());

// No security headers configured - dangerous!

app.get('/api/user/profile', (req, res) => {
  // This endpoint returns sensitive user data
  const userData = {
    id: req.user.id,
    email: req.user.email,
    apiKey: req.user.apiKey,
    oauthTokens: req.user.tokens
  };
  res.json(userData);
});

app.get('/dashboard', (req, res) => {
  // This page can be embedded in malicious iframes
  res.sendFile('dashboard.html');
});

app.listen(3000, () => {
  console.log('Server running on port 3000');
});
```

**Attack Payload** (Clickjacking via iframe embedding):
```html
<!-- Attacker's malicious page -->
<html>
<head><title>Win a Prize!</title></head>
<body>
  <h1>Click here to claim your prize!</h1>
  <!-- Hidden iframe overlays the "claim" button -->
  <iframe src="https://vulnerable-app.com/dashboard" 
          style="opacity: 0; position: absolute; top: 0; left: 0; 
                 width: 100%; height: 100%; z-index: 2;">
  </iframe>
  <button style="position: absolute; top: 200px; left: 100px; z-index: 1;">
    Claim Prize
  </button>
</body>
</html>
```

**Why This Is Dangerous**:
- **No X-Frame-Options**: Page can be embedded in malicious iframes for clickjacking attacks
- **No Content-Security-Policy**: No protection against XSS, no control over resource loading
- **No X-Content-Type-Options**: Browser may MIME-sniff responses, enabling XSS via uploaded files
- **No Strict-Transport-Security**: Allows downgrade attacks from HTTPS to HTTP
- **No X-XSS-Protection**: Legacy browsers lack XSS filtering (though modern browsers deprecate this)

**SECURE VERSION**:

```javascript
const express = require('express');
const helmet = require('helmet');
const app = express();

// Apply security headers via helmet middleware
app.use(helmet({
  // Prevent clickjacking
  frameguard: { action: 'deny' },

  // Content Security Policy
  contentSecurityPolicy: {
    directives: {
      defaultSrc: ["'self'"],
      scriptSrc: ["'self'"],
      styleSrc: ["'self'", "'unsafe-inline'"],
      imgSrc: ["'self'", 'data:', 'https:'],
      connectSrc: ["'self'"],
      fontSrc: ["'self'"],
      objectSrc: ["'none'"],
      frameAncestors: ["'none'"],
      upgradeInsecureRequests: []
    }
  },

  // Prevent MIME sniffing
  noSniff: true,

  // Force HTTPS
  hsts: {
    maxAge: 31536000,
    includeSubDomains: true,
    preload: true
  },

  // Referrer policy
  referrerPolicy: { policy: 'strict-origin-when-cross-origin' },

  // Don't advertise Express
  hidePoweredBy: true
}));

app.use(express.json());

app.get('/api/user/profile', (req, res) => {
  const userData = {
    id: req.user.id,
    email: req.user.email
    // Note: Never expose API keys or tokens in responses
  };
  res.json(userData);
});

app.listen(3000, () => {
  console.log('Secure server running on port 3000');
});
```

**Key Security Controls**:
- **helmet() middleware**: Applies multiple security headers with sensible defaults
- **X-Frame-Options: DENY**: Prevents all iframe embedding, blocking clickjacking
- **Content-Security-Policy**: Restricts where resources can load from, mitigates XSS
- **Strict-Transport-Security**: Forces HTTPS for all future requests
- **X-Content-Type-Options: nosniff**: Prevents MIME-type confusion attacks

Great questions! These are common production challenges. You'll need to carefully configure frame-ancestors and use CSP nonces or hashes for inline scripts in your React SPA.

**PRODUCTION PATTERN**:

```javascript
const express = require('express');
const helmet = require('helmet');
const crypto = require('crypto');
const winston = require('winston');
const rateLimit = require('express-rate-limit');

const app = express();

// Configure structured logging
const logger = winston.createLogger({
  level: process.env.LOG_LEVEL || 'info',
  format: winston.format.combine(
    winston.format.timestamp(),
    winston.format.json()
  ),
  transports: [
    new winston.transports.File({ filename: 'security.log' })
  ]
});

// Generate CSP nonce for each request
app.use((req, res, next) => {
  res.locals.cspNonce = crypto.randomBytes(32).toString('base64');
  next();
});

// Trusted domains for iframe embedding (e.g., partner sites)
const TRUSTED_FRAME_ANCESTORS = [
  "'self'",
  'https://trusted-partner.com',
  'https://internal-dashboard.company.com'
];

// Environment-specific CSP configuration
const getCSPConfig = (req, res) => {
  const isDev = process.env.NODE_ENV !== 'production';
  const nonce = res.locals.cspNonce;

  return {
    directives: {
      defaultSrc: ["'self'"],

      // Allow scripts with nonce (for React inline scripts)
      scriptSrc: [
        "'self'",
        `'nonce-${nonce}'`,
        // In dev, allow React DevTools
        ...(isDev ? ["'unsafe-eval'"] : [])
      ],

      // Styles - allow inline for styled-components with nonce
      styleSrc: [
        "'self'",
        `'nonce-${nonce}'`,
        // Google Fonts if needed
        'https://fonts.googleapis.com'
      ],

      // Images
      imgSrc: [
        "'self'",
        'data:',
        'blob:',
        'https://cdn.company.com',
        'https://*.cloudinary.com'
      ],

      // API connections
      connectSrc: [
        "'self'",
        'https://api.company.com',
        // WebSocket for hot reload in dev
        ...(isDev ? ['ws://localhost:*'] : [])
      ],

      // Fonts
      fontSrc: ["'self'", 'https://fonts.gstatic.com'],

      // No plugins (Flash, etc.)
      objectSrc: ["'none'"],

      // Media
      mediaSrc: ["'self'", 'https://media.company.com'],

      // Workers
      workerSrc: ["'self'", 'blob:'],

      // Frame ancestors - who can embed us
      frameAncestors: isDev ? ["'self'"] : TRUSTED_FRAME_ANCESTORS,

      // Where we can be embedded as iframe src
      frameSrc: ["'self'", 'https://www.youtube.com', 'https://player.vimeo.com'],

      // Form submission targets
      formAction: ["'self'"],

      // Base URI restriction
      baseUri: ["'self'"],

      // Upgrade HTTP to HTTPS
      upgradeInsecureRequests: isDev ? [] : true,

      // Report violations
      reportUri: '/api/csp-report'
    }
  };
};

// Apply helmet with dynamic CSP
app.use((req, res, next) => {
  helmet({
    contentSecurityPolicy: getCSPConfig(req, res),

    frameguard: false, // Using CSP frame-ancestors instead

    hsts: {
      maxAge: 63072000, // 2 years
      includeSubDomains: true,
      preload: true
    },

    noSniff: true,

    referrerPolicy: {
      policy: 'strict-origin-when-cross-origin'
    },

    // Cross-Origin policies for additional isolation
    crossOriginEmbedderPolicy: false, // Enable if not using cross-origin resources
    crossOriginOpenerPolicy: { policy: 'same-origin' },
    crossOriginResourcePolicy: { policy: 'same-origin' },

    // Permissions Policy (formerly Feature-Policy)
    permissionsPolicy: {
      features: {
        geolocation: ["'self'"],
        camera: ["'none'"],
        microphone: ["'none'"],
        payment: ["'self'"],
        usb: ["'none'"]
      }
    },

    hidePoweredBy: true
  })(req, res, next);
});

// Rate limiting
const limiter = rateLimit({
  windowMs: 15 * 60 * 1000, // 15 minutes
  max: 100,
  standardHeaders: true,
  legacyHeaders: false
});
app.use(limiter);

app.use(express.json({ limit: '10kb' }));

// CSP violation reporting endpoint
app.post('/api/csp-report', express.json({ type: 'application/csp-report' }), (req, res) => {
  const violation = req.body['csp-report'] || req.body;

  logger.warn('CSP Violation', {
    blockedUri: violation['blocked-uri'],
    violatedDirective: violation['violated-directive'],
    documentUri: violation['document-uri'],
    sourceFile: violation['source-file'],
    lineNumber: violation['line-number'],
    userAgent: req.headers['user-agent'],
    ip: req.ip
  });

  res.status(204).end();
});

// Serve React app with nonce injection
app.get('*', (req, res) => {
  const nonce = res.locals.cspNonce;

  // In production, read from built index.html and inject nonce
  const html = `
    <!DOCTYPE html>
    <html lang="en">
    <head>
      <meta charset="UTF-8">
      <meta name="viewport" content="width=device-width, initial-scale=1.0">
      <title>Secure App</title>
      <link rel="stylesheet" href="/static/css/main.css">
    </head>
    <body>
      <div id="root"></div>
      <script nonce="${nonce}">
        window.__INITIAL_STATE__ = {};
      </script>
      <script nonce="${nonce}" src="/static/js/main.js"></script>
    </body>
    </html>
  `;

  res.send(html);
});

// Security headers verification middleware
app.use((req, res, next) => {
  res.on('finish', () => {
    const securityHeaders = [
      'content-security-policy',
      'strict-transport-security',
      'x-content-type-options',
      'x-frame-options',
      'referrer-policy'
    ];

    const missingHeaders = securityHeaders.filter(
      header => !res.getHeader(header)
    );

    if (missingHeaders.length > 0) {
      logger.error('Missing security headers', {
        path: req.path,
        missingHeaders,
        statusCode: res.statusCode
      });
    }
  });
  next();
});

const PORT = process.env.PORT || 3000;
app.listen(PORT, () => {
  logger.info(`Secure server started on port ${PORT}`, {
    environment: process.env.NODE_ENV,
    nodeVersion: process.version
  });
});
```

